script:
action = frappe.form_dict.get("action")
card_name = frappe.form_dict.get("card_name")
reason = frappe.form_dict.get("reason")

card = frappe.get_doc("Hostel Card", card_name)

if action == "block":
    frappe.db.set_value("Hostel Card", card_name, "card_status", "Blocked")
    if reason:
        frappe.db.set_value("Hostel Card", card_name, "remarks", reason)
    frappe.response["message"] = {"status": "Card Blocked"}

elif action == "expire":
    frappe.db.set_value("Hostel Card", card_name, "card_status", "Expired")
    if reason:
        frappe.db.set_value("Hostel Card", card_name, "remarks", reason)
    frappe.response["message"] = {"status": "Card Expired"}

elif action == "reissue":
    new_card = frappe.get_doc({"doctype": "Hostel Card", "student": card.student, "hostel_admission": card.hostel_admission, "card_status": "Active", "issue_date": frappe.utils.today(), "previous_card": card.name, "remarks": reason})
    new_card.insert(ignore_permissions=True)
    frappe.response["message"] = {"status": "New Card Created", "new_card": new_card.name}

else:
    frappe.throw("Invalid action")
